mapper.select:
select piicode, piigradeid, piigradename, piigroupid, piigroupname, piitypeid, piitypename, scrtype, scrmethod, scrcategory, scrdigits, scrvalidity, remarks, encdecfunctype, encfunc, decfunc, visible
  from cotdl.tbl_lkpiiscrtype
 where piicode= #{piicode, jdbcType=VARCHAR}

mapper.update:
update cotdl.tbl_lkpiiscrtype
   set visible = #{visible, jdbcType=CHAR}
 where piicode = #{piicode, jdbcType=VARCHAR}
